@Composable
fun AdaptiveMessageScreen(
    windowSizeClass: WindowWidthSizeClass,
    messages: List<Message>,
    selectedId: String?,
    onSelect: (String) -> Unit
) {
    when (windowSizeClass) {
        WindowWidthSizeClass.Compact -> {
            // Phone: show list only (navigate to detail on tap)
            MessageList(messages, selectedId, onSelect)
        }
        else -> {
            // Tablet: side-by-side list + detail
            Row(modifier = Modifier.fillMaxSize()) {
                MessageList(
                    messages, selectedId, onSelect,
                    modifier = Modifier.weight(1f)
                )
                val selected = messages.find { it.id == selectedId }
                if (selected != null) {
                    MessageDetail(
                        message = selected,
                        modifier = Modifier.weight(2f)
                    )
                }
            }
        }
    }
}
